        ]
    }()
    
    static func generateMnemonic(wordCount: Int = 12) -> String? {
        guard wordCount == 12 || wordCount == 24 else { return nil }
        let entropyBytes = wordCount == 12 ? 16 : 32
        
        var entropy = Data(count: entropyBytes)
        let result = entropy.withUnsafeMutableBytes { bufferPointer in
            SecRandomCopyBytes(kSecRandomDefault, entropyBytes, bufferPointer.baseAddress!)
        }
        
        guard result == errSecSuccess else { return nil }
        
        let hash = SHA256.hash(data: entropy)
        let hashData = Data(hash)
        
        var bits = ""
        for byte in entropy {
            bits += String(byte, radix: 2).leftPadded(toLength: 8, withPad: "0")
        }
        
        let checksumBits = wordCount == 12 ? 4 : 8
        let firstByte = hashData[0]
        let checksumString = String(firstByte, radix: 2).leftPadded(toLength: 8, withPad: "0")
        bits += String(checksumString.prefix(checksumBits))
        
        var words: [String] = []
        let totalWords = bits.count / 11
        
        for i in 0..<totalWords {
            let startIndex = bits.index(bits.startIndex, offsetBy: i * 11)
            let endIndex = bits.index(startIndex, offsetBy: 11)
            let indexBits = String(bits[startIndex..<endIndex])
            
            guard let wordIndex = Int(indexBits, radix: 2), wordIndex < wordList.count else {
                return nil
            }
            words.append(wordList[wordIndex])
        }
        
        return words.joined(separator: " ")
    }
    
    static func deriveKeyFromMnemonic(_ mnemonic: String, passphrase: String = "") -> Data? {
        let mnemonicData = Data(mnemonic.decomposedStringWithCompatibilityMapping.utf8)
        let salt = Data(("mnemonic" + passphrase).decomposedStringWithCompatibilityMapping.utf8)
        
        return pbkdf2(password: mnemonicData, salt: salt, iterations: 2048, keyLength: 64)
    }
    
    private static func pbkdf2(password: Data, salt: Data, iterations: Int, keyLength: Int) -> Data? {
        var derivedKey = Data(count: keyLength)
        
        let result = derivedKey.withUnsafeMutableBytes { derivedKeyBytes in
            password.withUnsafeBytes { passwordBytes in
                salt.withUnsafeBytes { saltBytes in
                    CCKeyDerivationPBKDF(
                        CCPBKDFAlgorithm(kCCPBKDF2),
                        passwordBytes.baseAddress?.assumingMemoryBound(to: Int8.self),
                        password.count,
                        saltBytes.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        salt.count,
                        CCPseudoRandomAlgorithm(kCCPRFHmacAlgSHA512),
                        UInt32(iterations),
                        derivedKeyBytes.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        keyLength
                    )
                }
            }
        }
        
        return result == kCCSuccess ? derivedKey : nil
    }
    
    // MARK: - Transaction Signing
    
    static func signTransaction(_ transactionData: Data, withPrivateKey privateKeyData: Data) -> Data? {
        guard let privateKey = try? P256.Signing.PrivateKey(rawRepresentation: privateKeyData) else {
            return nil
        }
        
        let digest = SHA256.hash(data: transactionData)
        
        guard let signature = try? privateKey.signature(for: digest) else {
            return nil
        }
        
        return signature.derRepresentation
    }
    
    static func verifySignature(_ signature: Data, forData data: Data, publicKey publicKeyData: Data) -> Bool {
        guard let publicKey = try? P256.Signing.PublicKey(compressedRepresentation: publicKeyData),
              let ecdsaSignature = try? P256.Signing.ECDSASignature(derRepresentation: signature) else {
            return false
        }
        
        let digest = SHA256.hash(data: data)
        return publicKey.isValidSignature(ecdsaSignature, for: digest)
    }
    
    // MARK: - Address Generation
    
    static func generateAddress(fromPublicKey publicKey: Data) -> String {
        let hash = SHA256.hash(data: publicKey)
        let addressData = Data(hash).prefix(20)
        return "0x" + addressData.map { String(format: "%02x", $0) }.joined()
    }
    
    // MARK: - Secure Data Wiping
    
    static func secureWipe(_ data: inout Data) {
        data.withUnsafeMutableBytes { buffer in
            if let baseAddress = buffer.baseAddress {
                memset_s(baseAddress, buffer.count, 0, buffer.count)
            }
        }
    }
}

extension String {
    func leftPadded(toLength length: Int, withPad pad: String) -> String {
        let deficit = length - self.count
        if deficit <= 0 { return self }
        return String(repeating: pad, count: deficit) + self
    }
}

// MARK: - Transaction.swift
import Foundation

struct Transaction: Codable, Identifiable {
    let id: String
    let from: String
    let to: String
    let amount: Decimal
    let fee: Decimal
    let timestamp: Date
    let nonce: UInt64
    var signature: Data?
    var status: TransactionStatus
    
    enum TransactionStatus: String, Codable {
        case pending
        case confirmed
        case failed
    }
    
    var serializedForSigning: Data {
        var components: [String] = [
            from,
            to,
            "\(amount)",
            "\(fee)",
            "\(nonce)",
            "\(Int(timestamp.timeIntervalSince1970))"
        ]
        let joined = components.joined(separator: "|")
        return Data(joined.utf8)
    }
    
    init(from: String, to: String, amount: Decimal, fee: Decimal, nonce: UInt64) {
        self.id = UUID().uuidString
        self.from = from
        self.to = to
        self.amount = amount
        self.fee = fee
        self.timestamp = Date()
        self.nonce = nonce
        self.signature = nil
        self.status = .pending
    }
}

