// MARK: - BlockchainService.swift
import Foundation

enum BlockchainError: Error, LocalizedError {
    case networkError(String)
    case invalidResponse
    case insufficientFunds
    case invalidAddress
    case transactionFailed(String)
    case rateLimited
    
    var errorDescription: String? {
        switch self {
        case .networkError(let msg): return "Network error: \(msg)"
        case .invalidResponse: return "Invalid response from blockchain"
        case .insufficientFunds: return "Insufficient funds"
        case .invalidAddress: return "Invalid address"
        case .transactionFailed(let msg): return "Transaction failed: \(msg)"
        case .rateLimited: return "Rate limited, please try again later"
        }
    }
}

actor BlockchainService {
    private let session: URLSession
    private let baseURL: String
    private var lastRequestTime: Date = .distantPast
    private let minRequestInterval: TimeInterval = 0.5
    
    init(baseURL: String = "https://api.example-blockchain.com/v1") {
        let config = URLSessionConfiguration.ephemeral
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.urlCache = nil
        config.httpCookieStorage = nil
        config.requestCachePolicy = .reloadIgnoringLocalCacheData
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        self.session = URLSession(configuration: config)
        self.baseURL = baseURL
    }
    
    private func rateLimitCheck() async throws {
        let now = Date()
        let elapsed = now.timeIntervalSince(lastRequestTime)
        if elapsed < minRequestInterval {
            try await Task.sleep(nanoseconds: UInt64((minRequestInterval - elapsed) * 1_000_000_000))
        }
        lastRequestTime = Date()
    }
    
    func getBalance(address: String) async throws -> Decimal {
        guard isValidAddress(address) else {
            throw BlockchainError.invalidAddress
        }
        
        try await rateLimitCheck()
        
        let url = URL(string: "\(baseURL)/balance/\(address)")!
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw BlockchainError.invalidResponse
        }
        
        if httpResponse.statusCode == 429 {
            throw BlockchainError.rateLimited
        }
        
        guard (200...299).contains(httpResponse.statusCode) else {
            throw BlockchainError.networkError("HTTP \(httpResponse.statusCode)")
        }
        
        let balanceResponse = try JSONDecoder().decode(BalanceResponse.self, from: data)
        return balanceResponse.balance
    }
    
    func broadcastTransaction(_ transaction: Transaction) async throws -> String {
        guard transaction.signature != nil else {
            throw BlockchainError.transactionFailed("Transaction not signed")
        }
        
        try await rateLimitCheck()
        
        let url = URL(string: "\(baseURL)/transactions/broadcast")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        request.httpBody = try encoder.encode(transaction)
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw BlockchainError.invalidResponse
        }
        
        if httpResponse.statusCode == 429 {
            throw BlockchainError.rateLimited
        }
        
        guard (200...299).contains(httpResponse.statusCode) else {
            throw BlockchainError.networkError("HTTP \(httpResponse.statusCode)")
        }
        
        let broadcastResponse = try JSONDecoder().decode(BroadcastResponse.self, from: data)
        return broadcastResponse.txHash
    }
    
    func getTransactionHistory(address: String, page: Int = 0, limit: Int = 20) async throws -> [Transaction] {
        guard isValidAddress(address) else {
            throw BlockchainError.invalidAddress
        }
        
        try await rateLimitCheck()
        
        let url = URL(string: "\(baseURL)/transactions/\(address)?page=\(page)&limit=\(limit)")!
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw BlockchainError.invalidResponse
        }
        
        guard (200...299).contains(httpResponse.statusCode) else {
            throw BlockchainError.networkError("HTTP \(httpResponse.statusCode)")
        }
        
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        return try decoder.decode([Transaction].self, from: data)
    }
    
    func getNonce(address: String) async throws -> UInt64 {
        guard isValidAddress(address) else {
            throw BlockchainError.invalidAddress
        }
        
        try await rateLimitCheck()
        
        let url = URL(string: "\(baseURL)/nonce/\(address)")!
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw BlockchainError.invalidResponse
        }
        
        guard (200...299).contains(httpResponse.statusCode) else {
            throw BlockchainError.networkError("HTTP \(httpResponse.statusCode)")
        }
        
        let nonceResponse = try JSONDecoder().decode(NonceResponse.self, from: data)
        return nonceResponse.nonce
    }
    
    private func isValidAddress(_ address: String) -> Bool {
        let pattern = "^0x[0-9a-fA-F]{40}$"
        return address.range(of: pattern, options: .regularExpression) != nil
    }
}

// MARK: - API Response Models
struct BalanceResponse: Codable {
    let balance: Decimal
    let address: String
}

struct BroadcastResponse: Codable {
    let txHash: String
    let status: String
}

struct NonceResponse: Codable {
    let nonce: UInt64
    let address: String
}

// MARK: - WalletManager.swift
import Foundation
import SwiftUI
import LocalAuthentication

enum WalletError: Error, LocalizedError {
    case keyGenerationFailed
    case mnemonicGenerationFailed
    case keyDerivationFailed
    case walletNotFound
    case signingFailed
    case biometricAuthFailed
    case invalidAmount
    case invalidRecipient
    
    var errorDescription: String? {
        switch self {
        case .keyGenerationFailed: return "Failed to generate keys"
        case .mnemonicGenerationFailed: return "Failed to generate recovery phrase"
        case .keyDerivationFailed: return "Failed to derive key from recovery phrase"
        case .walletNotFound: return "Wallet not found"
        case .signingFailed: return "Failed to sign transaction"
        case .biometricAuthFailed: return "Biometric authentication failed"
        case .invalidAmount: return "Invalid amount"
        case .invalidRecipient: return "Invalid recipient address"
        }
    }
}

@MainActor
class WalletManager: ObservableObject {
    @Published var wallets: [Wallet] = []
    @Published var selectedWallet: Wallet?
    @Published var transactions: [Transaction] = []
    @Published var isLoading = false
    @Published var errorMessage: String?
    @Published var showError = false
    
    private let keychainManager = KeychainManager.shared
    private let blockchainService = BlockchainService()
    private let walletsKey = "stored_wallets"
    
    init() {
        loadWallets()
    }
    
    // MARK: - Wallet Creation
    
    func createWallet(name: String) throws -> String {
        guard let mnemonic = CryptoUtils.generateMnemonic() else {
            throw WalletError.mnemonicGenerationFailed
        }
        
        guard var seed = CryptoUtils.deriveKeyFromMnemonic(mnemonic) else {
            throw WalletError.keyDerivationFailed
        }
        
        defer {
            CryptoUtils.secureWipe(&seed)
        }
        
        // Use first 32 bytes of seed as private key material
        var privateKeyData = seed.prefix(32)
        
        guard let keyPair = CryptoUtils.generateKeyPair() else {
            CryptoUtils.secureWipe(&privateKeyData)
            throw WalletError.keyGenerationFailed
        }
        
        let address = CryptoUtils.generateAddress(fromPublicKey: keyPair.publicKey)
        
        // Store private key securely in Keychain
        var privateKey = keyPair.privateKey
        defer {
            CryptoUtils.secureWipe(&privateKey)
        }
        
        try keychainManager.storePrivateKey(privateKey, forAccount: address)
        
        let wallet = Wallet(name: name, address: address, publicKey: keyPair.publicKey)
        wallets.append(wallet)
        
        if selectedWallet == nil {
            selectedWallet = wallet
        }
        
        saveWallets()
        
        return mnemonic
    }
    
    func importWallet(name: String, mnemonic: String) throws {
        guard var seed = CryptoUtils.deriveKeyFromMnemonic(mnemonic) else {
            throw WalletError.keyDerivationFailed
        }
        
        defer {
            CryptoUtils.secureWipe(&seed)
        }
        
        // Deterministic key from seed
        var privateKeyMaterial = seed.prefix(32)
        defer {
            CryptoUtils.secureWipe(&privateKeyMaterial)
        }
        
        guard let privateKey = try? P256.Signing.PrivateKey(rawRepresentation: privateKeyMaterial) else {
            throw WalletError.keyGenerationFailed
        }
        
        var privateKeyData = privateKey.rawRepresentation
        let publicKeyData = privateKey.publicKey.compressedRepresentation
        let address = CryptoUtils.generateAddress(fromPublicKey: publicKeyData)
        
        defer {
            CryptoUtils.secureWipe(&privateKeyData)
        }
        
        try keychainManager.storePrivateKey(privateKeyData, forAccount: address)
        
        let wallet = Wallet(name: name, address: address, publicKey: publicKeyData)
        wallets.append(wallet)
        
        if selectedWallet == nil {
            selectedWallet = wallet
        }
        
        saveWallets()
    }
    
    // MARK: - Transaction Signing & Sending
    
    func sendTransaction(to recipient: String, amount: Decimal, fee: Decimal) async throws -> String {
        guard let wallet = selectedWallet else {
            throw WalletError.walletNotFound
        }
        
        guard amount > 0 else {
            throw WalletError.invalidAmount
        }
        
        let addressPattern = "^0x[0-9a-fA-F]{40}$"
        guard recipient.range(of: addressPattern, options: .regularExpression) != nil else {
            throw WalletError.invalidRecipient
        }
        
        guard wallet.balance >= (amount + fee) else {
            throw BlockchainError.insufficientFunds
        }
        
        // Authenticate with biometrics before signing
        try await authenticateWithBiometrics()
        
        let nonce = try await blockchainService.getNonce(address: wallet.address)
        
        var transaction = Transaction(
            from: wallet.address,
            to: recipient,
            amount: amount,
            fee: fee,
            nonce: nonce
        )
        
        // Sign the transaction
        var privateKeyData = try keychainManager.retrievePrivateKey(forAccount: wallet.address)
        defer {
            CryptoUtils.secureWipe(&privateKeyData)
        }
        
        let transactionData = transaction.serializedForSigning
        
        guard let signature = CryptoUtils.signTransaction(transactionData, withPrivateKey: privateKeyData) else {
            throw WalletError.signingFailed
        }
        
        // Verify signature before broadcasting
        guard CryptoUtils.verifySignature(signature, forData: transactionData, publicKey: wallet.publicKey) else {
            throw WalletError.signingFailed
        }
        
        transaction.signature = signature
        
        let txHash = try await blockchainService.broadcastTransaction(transaction)
        
        transactions.insert(transaction, at: 0)
        
        return txHash
    }
    
    // MARK: - Balance & History
    
    func refreshBalance() async {
        guard let wallet = selectedWallet else { return }
        
        isLoading = true
        defer { isLoading = false }
        
        do {
            let balance = try await blockchainService.getBalance(address: wallet.address)
            if let index = wallets.firstIndex(where: { $0.id == wallet.id }) {
                wallets[index].balance = balance
                selectedWallet = wallets[index]
            }
        } catch {
            showErrorMessage(error.localizedDescription)
        }
    }
    
    func refreshTransactions() async {
        guard let wallet = selectedWallet else { return }
        
        isLoading = true
        defer { isLoading = false }
        
        do {
            let history = try await blockchainService.getTransactionHistory(address: wallet.address)
            transactions = history
        } catch {
            showErrorMessage(error.localizedDescription)
        }
    }
    
    // MARK: - Wallet Management
    
    func deleteWallet(_ wallet: Wallet) throws {
        try keychainManager.deletePrivateKey(forAccount: wallet.address)
        wallets.removeAll { $0.id == wallet.id }
        
        if selectedWallet?.id == wallet.id {
            selectedWallet = wallets.first
        }
        
        saveWallets()
    }
    
    func selectWallet(_ wallet: Wallet) {
        selectedWallet = wallet
        transactions = []
    }
    
    // MARK: - Biometric Authentication
    
    private func authenticateWithBiometrics() async throws {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            // Fall back to passcode
            guard context.canEvaluatePolicy(.deviceOwnerAuthentication, error: &error) else {
                throw WalletError.biometricAuthFailed
            }
            
            let success = try await context.evaluatePolicy(
                .deviceOwnerAuthentication,
                localizedReason: "Authenticate to sign transaction"
            )
            
            guard success else {
                throw WalletError.biometricAuthFailed
            }
            return
        }
        
        let success = try await context.evaluatePolicy(
            .deviceOwnerAuthenticationWithBiometrics,
            localizedReason: "Authenticate to sign transaction"
        )
        
        guard success else {
            throw WalletError.biometricAuthFailed
        }
    }
    
    // MARK: - Persistence
    
    private func saveWallets() {
        if let data = try? JSONEncoder().encode(wallets) {
            UserDefaults.standard.set(data, forKey: walletsKey)
        }
    }
    
    private func loadWallets() {
        guard let data = UserDefaults.standard.data(forKey: walletsKey),
              let decoded = try? JSONDecoder().decode([Wallet].self, from: data) else {
            return
        }
        wallets = decoded
        selectedWallet = wallets.first
    }
    
    private func showErrorMessage(_ message: String) {
        errorMessage = message
        showError = true
    }
}

