                                ForEach(walletManager.wallets) { w in
                                    Button(action: {
                                        walletManager.selectWallet(w)
                                    }) {
                                        Text(w.name)
                                            .padding(.horizontal, 16)
                                            .padding(.vertical, 8)
                                            .background(
                                                Capsule()
                                                    .fill(w.id == wallet.id ? Color.blue : Color.gray.opacity(0.2))
                                            )
                                            .foregroundColor(w.id == wallet.id ? .white : .primary)
                                    }
                                }
                            }
                            .padding(.horizontal)
                        }
                    }
                    
                    Button(action: {
                        Task {
                            await walletManager.refreshBalance()
                        }
                    }) {
                        HStack {
                            Image(systemName: "arrow.clockwise")
                            Text("Refresh Balance")
                        }
                        .frame(maxWidth: .infinity)
                        .padding()
                        .background(Color.blue.opacity(0.1))
                        .cornerRadius(12)
                    }
                    .padding(.horizontal)
                    .disabled(walletManager.isLoading)
                    
                    Spacer()
                } else {
                    Spacer()
                    
                    VStack(spacing: 16) {
                        Image(systemName: "wallet.pass")
                            .font(.system(size: 60))
                            .foregroundColor(.gray)
                        
                        Text("No Wallet Found")
                            .font(.title2)
                            .fontWeight(.semibold)
                        
                        Text("Create a new wallet or import an existing one")
                            .font(.subheadline)
                            .foregroundColor(.secondary)
                            .multilineTextAlignment(.center)
                    }
                    
                    Spacer()
                }
                
                VStack(spacing: 12) {
                    Button(action: { showCreateWallet = true }) {
                        Text("Create New Wallet")
                            .fontWeight(.semibold)
                            .frame(maxWidth: .infinity)
                            .padding()
                            .background(Color.blue)
                            .foregroundColor(.white)
                            .cornerRadius(12)
                    }
                    
                    Button(action: { showImportWallet = true }) {
                        Text("Import Wallet")
                            .fontWeight(.semibold)
                            .frame(maxWidth: .infinity)
                            .padding()
                            .background(Color.gray.opacity(0.2))
                            .foregroundColor(.primary)
                            .cornerRadius(12)
                    }
                }
                .padding(.horizontal)
                .padding(.bottom)
            }
            .navigationTitle("Wallet")
            .sheet(isPresented: $showCreateWallet) {
                CreateWalletSheet(showMnemonic: $showMnemonic, generatedMnemonic: $generatedMnemonic)
            }
            .sheet(isPresented: $showImportWallet) {
                ImportWalletSheet()
            }
            .sheet(isPresented: $showMnemonic) {
                MnemonicDisplaySheet(mnemonic: generatedMnemonic)
