// MARK: - CreateWalletSheet.swift
import SwiftUI

struct CreateWalletSheet: View {
    @EnvironmentObject var walletManager: WalletManager
    @Environment(\.dismiss) var dismiss
    @Binding var showMnemonic: Bool
    @Binding var generatedMnemonic: String
    @State private var walletName = ""
    @State private var errorMessage: String?
    
    var body: some View {
        NavigationView {
            Form {
                Section("Wallet Name") {
                    TextField("My Wallet", text: $walletName)
                        .autocorrectionDisabled()
                }
                
                if let error = errorMessage {
                    Section {
                        Text(error)
                            .foregroundColor(.red)
                    }
                }
                
                Section {
                    Button("Create Wallet") {
                        createWallet()
                    }
                    .disabled(walletName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                }
                
                Section {
                    Text("⚠️ You will be shown a recovery phrase. Write it down and store it safely. It is the only way to recover your wallet.")
                        .font(.caption)
                        .foregroundColor(.orange)
                }
            }
            .navigationTitle("Create Wallet")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Cancel") { dismiss() }
                }
            }
        }
    }
    
    private func createWallet() {
        do {
            let mnemonic = try walletManager.createWallet(name: walletName.trimmingCharacters(in: .whitespacesAndNewlines))
            generatedMnemonic = mnemonic
            dismiss()
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) {
                showMnemonic = true
            }
        } catch {
            errorMessage = error.localizedDescription
        }
    }
}

