// MARK: - ImportWalletSheet.swift
import SwiftUI

struct ImportWalletSheet: View {
    @EnvironmentObject var walletManager: WalletManager
    @Environment(\.dismiss) var dismiss
    @State private var walletName = ""
    @State private var mnemonic = ""
    @State private var errorMessage: String?
    @State private var isImporting = false
    
    var body: some View {
        NavigationView {
            Form {
                Section("Wallet Name") {
                    TextField("My Wallet", text: $walletName)
                        .autocorrectionDisabled()
                }
                
                Section("Recovery Phrase") {
                    TextEditor(text: $mnemonic)
                        .frame(minHeight: 100)
                        .autocorrectionDisabled()
                        .textInputAutocapitalization(.never)
                }
                
                if let error = errorMessage {
                    Section {
                        Text(error)
                            .foregroundColor(.red)
                    }
                }
                
                Section {
                    Button("Import Wallet") {
                        importWallet()
                    }
                    .disabled(walletName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ||
                              mnemonic.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ||
                              isImporting)
                }
            }
            .navigationTitle("Import Wallet")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Cancel") { dismiss() }
                }
            }
        }
    }
    
    private func importWallet() {
        isImporting = true
        errorMessage = nil
        
        let trimmedName = walletName.trimmingCharacters(in: .whitespacesAndNewlines)
        let trimmedMnemonic = mnemonic.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        
        let words = trimmedMnemonic.split(separator: " ")
        guard words.count == 12 || words.count == 24 else {
            errorMessage = "Recovery phrase must be 12 or 24 words"
            isImporting = false
            return
        }
        
        do {
            try walletManager.importWallet(name: trimmedName, mnemonic: trimmedMnemonic)
            dismiss()
        } catch {
            errorMessage = error.localizedDescription
        }
        
        isImporting = false
    }
}

// MARK: - SendView.swift
import SwiftUI

struct SendView: View {
    @EnvironmentObject var walletManager: WalletManager
    @State private var recipientAddress = ""
    @State private var amount = ""
    @State private var fee = "0.001"
    @State private var isSending = false
    @State private var showConfirmation = false
    @State private var txHash: String?
    @State private var errorMessage: String?
    
    var body: some View {
        NavigationView {
            Form {
                if let wallet = walletManager.selectedWallet {
                    Section("From") {
                        VStack(alignment: .leading) {
                            Text(wallet.name)
                                .fontWeight(.medium)
                            Text(wallet.address)
                                .font(.caption)
                                .foregroundColor(.secondary)
                            Text("Balance: \(wallet.balance as NSDecimalNumber) ETH")
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                    }
                    
                    Section("Recipient") {
                        TextField("0x...", text: $recipientAddress)
                            .autocorrectionDisabled()
                            .textInputAutocapitalization(.never)
                            .font(.system(.body, design: .monospaced))
                    }
                    
                    Section("Amount (ETH)") {
                        TextField("0.0", text: $amount)
                            .keyboardType(.decimalPad)
                    }
                    
                    Section("Fee (ETH)") {
                        TextField("0.001", text: $fee)
                            .keyboardType(.decimalPad)
                    }
                    
                    if let error = errorMessage {
                        Section {
                            Text(error)
                                .foregroundColor(.red)
                        }
                    }
                    
                    if let hash = txHash {
                        Section("Transaction Sent") {
                            VStack(alignment: .leading) {
                                Text("TX Hash:")
                                    .font(.caption)
                                    .foregroundColor(.secondary)
                                Text(hash)
                                    .font(.system(.caption, design: .monospaced))
                                    .foregroundColor(.green)
                            }
                        }
                    }
                    
                    Section {
                        Button(action: { showConfirmation = true }) {
                            HStack {
                                Spacer()
                                if isSending {
                                    ProgressView()
                                } else {
                                    Text("Send Transaction")
                                        .fontWeight(.semibold)
                                }
                                Spacer()
                            }
                        }
                        .disabled(isSending || !isValidInput)
                    }
                } else {
                    Section {
                        Text("Please create or import a wallet first")
                            .foregroundColor(.secondary)
                    }
                }
            }
            .navigationTitle("Send")
            .alert("Confirm Transaction", isPresented: $showConfirmation) {
                Button("Cancel", role: .cancel) {}
                Button("Send") {
                    sendTransaction()
                }
            } message: {
                Text("Send \(amount) ETH to \(truncatedAddress(recipientAddress))?")
            }
        }
    }
    
    private var isValidInput: Bool {
        let addressPattern = "^0x[0-9a-fA-F]{40}$"
        let validAddress = recipientAddress.range(of: addressPattern, options: .regularExpression) != nil
        let validAmount = Decimal(string: amount) != nil && (Decimal(string: amount) ?? 0) > 0
        let validFee = Decimal(string: fee) != nil && (Decimal(string: fee) ?? 0) > 0
        return validAddress && validAmount && validFee
    }
    
    private func sendTransaction() {
        isSending = true
        errorMessage = nil
        txHash = nil
        
        Task {
            do {
                guard let amountDecimal = Decimal(string: amount),
                      let feeDecimal = Decimal(string: fee) else {
                    errorMessage = "Invalid amount"
                    isSending = false
                    return
                }
                
                let hash = try await walletManager.sendTransaction(
                    to: recipientAddress,
                    amount: amountDecimal,
                    fee: feeDecimal
                )
                
                txHash = hash
                amount = ""
                recipientAddress = ""
            } catch {
                errorMessage = error.localizedDescription
            }
            
            isSending = false
        }
    }
    
    private func truncatedAddress(_ address: String) -> String {
        guard address.count > 12 else { return address }
        return "\(address.prefix(8))...\(address.suffix(6))"
    }
}

