struct TransactionRow: View {
    let transaction: Transaction
    let walletAddress: String
    
    var isSent: Bool {
        transaction.from.lowercased() == walletAddress.lowercased()
    }
    
    var body: some View {
        HStack {
            Image(systemName: isSent ? "arrow.up.circle.fill" : "arrow.down.circle.fill")
                .foregroundColor(isSent ? .red : .green)
                .font(.title2)
            
            VStack(alignment: .leading, spacing: 4) {
                Text(isSent ? "Sent" : "Received")
                    .fontWeight(.medium)
                
                Text(truncatedAddress(isSent ? transaction.to : transaction.from))
                    .font(.caption)
                    .foregroundColor(.secondary)
                
                Text(transaction.timestamp, style: .relative)
                    .font(.caption2)
                    .foregroundColor(.secondary)
            }
            
            Spacer()
            
            VStack(alignment: .trailing, spacing: 4) {
                Text("\(isSent ? "-" : "+")\(transaction.amount as NSDecimalNumber) ETH")
                    .fontWeight(.semibold)
                    .foregroundColor(isSent ? .red : .green)
                
                StatusBadge(status: transaction.status)
            }
        }
        .padding(.vertical, 4)
    }
    
    private func truncatedAddress(_ address: String) -> String {
        guard address.count > 12 else { return address }
        return "\(address.prefix(6))...\(address.suffix(4))"
    }
}

struct StatusBadge: View {
    let status: Transaction.TransactionStatus
    
    var color: Color {
        switch status {
        case .pending: return .orange
        case .confirmed: return .green
        case .failed: return .red
        }
    }
    
    var body: some View {
        Text(status.rawValue.capitalized)
            .font(.caption2)
            .fontWeight(.medium)
            .padding(.horizontal, 8)
            .padding(.vertical, 2)
            .background(color.opacity(0.2))
            .foregroundColor(color)
            .cornerRadius(4)
    }
}

